INSERT INTO `nl_queries` (`id`, `user_id`, `natural_language_query`, `generated_sql`, `query_result`, `query_results_formatted`, `result_columns`, `result_count`, `show_sql_to_user`, `query_status`, `error_message`, `execution_time`, `query_intent`, `created_at`, `updated_at`) VALUES
(1, 1, 'Show students below 75% attendance', '\r\n            SELECT DISTINCT s.id, u.name, c.course_name, \r\n                   COUNT(CASE WHEN a.status = \'present\' THEN 1 END) * 100.0 / COUNT(*) as attendance_percentage\r\n            FROM students s\r\n            JOIN users u ON s.user_id = u.id\r\n            JOIN attendance a ON s.id = a.student_id\r\n            JOIN courses c ON a.course_id = c.id\r\n            GROUP BY s.id, u.name, c.course_name\r\n            HAVING attendance_percentage < 60\r\n            ORDER BY attendance_percentage ASC\r\n        ', '\"[{\\\"id\\\":21,\\\"name\\\":\\\"Kankanala Anand\\\",\\\"course_name\\\":\\\"Computer Networks & Security\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":48,\\\"name\\\":\\\"Nalluri Tarun\\\",\\\"course_name\\\":\\\"Object Oriented Software Engg.\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":50,\\\"name\\\":\\\"Bodapati Manish\\\",\\\"course_name\\\":\\\"Web Tech & Python Lab\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":120,\\\"name\\\":\\\"Rayapati Ramya\\\",\\\"course_name\\\":\\\"IT Problem Solving Lab\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":147,\\\"name\\\":\\\"Gogineni Vyshnavi\\\",\\\"course_name\\\":\\\"Web Architecture & HTTP\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":149,\\\"name\\\":\\\"Duddu Prathyusha\\\",\\\"course_name\\\":\\\"Web Architecture Lab\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":169,\\\"name\\\":\\\"Gattamaneni Phani\\\",\\\"course_name\\\":\\\"Business Environment & Law\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":198,\\\"name\\\":\\\"Nalluri Tarun\\\",\\\"course_name\\\":\\\"Financial Statement Analysis Lab\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":73,\\\"name\\\":\\\"Rachapudi Pavan\\\",\\\"course_name\\\":\\\"Programming in C & Data Struct\\\",\\\"attendance_percentage\\\":\\\"0.00000\\\"},{\\\"id\\\":75,\\\"name\\\":\\